import { GenerationOptions, PasswordStrength } from '@/types';

const CHAR_SETS = {
  uppercase: 'ABCDEFGHIJKLMNOPQRSTUVWXYZ',
  lowercase: 'abcdefghijklmnopqrstuvwxyz',
  numbers: '0123456789',
  symbols: '!@#$%^&*()_+-=[]{}|;:,.<>?',
};

function secureRandomInt(max: number): number {
  const array = new Uint32Array(1);
  crypto.getRandomValues(array);
  return array[0] % max;
}

export function generatePassword(options: GenerationOptions): {
  password: string;
  strength: PasswordStrength;
  poolSize: number;
} {
  const { length, includeUppercase, includeLowercase, includeNumbers, includeSymbols } = options;

  let charPool = '';
  let poolSize = 0;

  if (includeUppercase) { charPool += CHAR_SETS.uppercase; poolSize += 26; }
  if (includeLowercase) { charPool += CHAR_SETS.lowercase; poolSize += 26; }
  if (includeNumbers) { charPool += CHAR_SETS.numbers; poolSize += 10; }
  if (includeSymbols) { charPool += CHAR_SETS.symbols; poolSize += 32; }

  if (charPool.length === 0) throw new Error('At least one character set must be selected');
  if (length < 4 || length > 128) throw new Error('Password length must be between 4 and 128');

  let password = '';
  if (includeUppercase) password += CHAR_SETS.uppercase[secureRandomInt(26)];
  if (includeLowercase) password += CHAR_SETS.lowercase[secureRandomInt(26)];
  if (includeNumbers) password += CHAR_SETS.numbers[secureRandomInt(10)];
  if (includeSymbols) password += CHAR_SETS.symbols[secureRandomInt(32)];

  while (password.length < length) {
    password += charPool[secureRandomInt(charPool.length)];
  }

  const passwordArray = password.split('');
  for (let i = passwordArray.length - 1; i > 0; i--) {
    const j = secureRandomInt(i + 1);
    [passwordArray[i], passwordArray[j]] = [passwordArray[j]!, passwordArray[i]!];
  }

  const charTypes = [includeUppercase, includeLowercase, includeNumbers, includeSymbols].filter(Boolean).length;
  let strength: PasswordStrength;
  if (length < 8 || charTypes < 2) strength = 'weak';
  else if (length < 12 && charTypes < 3) strength = 'fair';
  else if (length >= 12 && charTypes >= 3) {
    if (length >= 20 && charTypes === 4) strength = 'excellent';
    else if (length >= 16) strength = 'strong';
    else strength = 'good';
  } else strength = 'fair';

  return { password: passwordArray.join(''), strength, poolSize };
}

export function calculatePoolSize(password: string): number {
  let size = 0;
  if (/[A-Z]/.test(password)) size += 26;
  if (/[a-z]/.test(password)) size += 26;
  if (/[0-9]/.test(password)) size += 10;
  if (/[^A-Za-z0-9]/.test(password)) size += 32;
  return size || 1;
}

export function validatePasswordStrength(password: string) {
  const feedback: string[] = [];
  let score = 0;

  if (password.length < 8) feedback.push('Password should be at least 8 characters');
  else if (password.length >= 12) score += 2;
  else score += 1;

  const hasUpper = /[A-Z]/.test(password);
  const hasLower = /[a-z]/.test(password);
  const hasNumber = /[0-9]/.test(password);
  const hasSymbol = /[^A-Za-z0-9]/.test(password);

  const variety = [hasUpper, hasLower, hasNumber, hasSymbol].filter(Boolean).length;
  if (!hasUpper) feedback.push('Add uppercase letters');
  if (!hasLower) feedback.push('Add lowercase letters');
  if (!hasNumber) feedback.push('Add numbers');
  if (!hasSymbol) feedback.push('Add special characters');

  score += variety;

  let strength: PasswordStrength;
  if (score <= 2) strength = 'weak';
  else if (score <= 3) strength = 'fair';
  else if (score <= 4) strength = 'good';
  else if (score <= 5) strength = 'strong';
  else strength = 'excellent';

  return { score, feedback, strength, poolSize: calculatePoolSize(password) };
}
