import { validatePasswordStrength } from './passwordGenerator';
import type { PasswordEntry, ValidationResult, ValidationRules } from '@/types';

export const DEFAULT_VALIDATION_RULES: ValidationRules = {
  required: ['name', 'username', 'password'],
  minLength: { name: 2, username: 3, password: 8 },
  maxLength: { name: 100, username: 255, password: 128, notes: 5000 },
  pattern: { url: /^(https?:\/\/)?[\w\-]+(\.[\w\-]+)+[/#?]?.*$/ },
  custom: {
    password: (value: string) => {
      if (!value) return 'Password is required';
      const { strength, feedback } = validatePasswordStrength(value);
      if (strength === 'weak') return `Password is too weak: ${feedback.join('; ')}`;
      return null;
    },
  },
};

export function validateEntry(entry: Partial<PasswordEntry>, rules: ValidationRules = DEFAULT_VALIDATION_RULES): ValidationResult {
  const errors: Record<string, string[]> = {};

  if (rules.required) {
    for (const field of rules.required) {
      const value = entry[field as keyof PasswordEntry];
      if (!value || (typeof value === 'string' && value.trim() === '')) {
        errors[field] = [`${field} is required`];
      }
    }
  }

  if (rules.minLength) {
    for (const [field, min] of Object.entries(rules.minLength)) {
      const value = entry[field as keyof PasswordEntry];
      if (value && typeof value === 'string' && value.length < min) {
        errors[field] = [`${field} must be at least ${min} characters`];
      }
    }
  }

  if (rules.maxLength) {
    for (const [field, max] of Object.entries(rules.maxLength)) {
      const value = entry[field as keyof PasswordEntry];
      if (value && typeof value === 'string' && value.length > max) {
        errors[field] = [`${field} must be no more than ${max} characters`];
      }
    }
  }

  if (rules.pattern) {
    for (const [field, regex] of Object.entries(rules.pattern)) {
      const value = entry[field as keyof PasswordEntry];
      if (value && typeof value === 'string' && !regex.test(value)) {
        errors[field] = [`${field} format is invalid`];
      }
    }
  }

  if (rules.custom) {
    for (const [field, validator] of Object.entries(rules.custom)) {
      const value = entry[field as keyof PasswordEntry];
      const error = validator(value);
      if (error) {
        errors[field] = [error];
      }
    }
  }

  return { valid: Object.keys(errors).length === 0, errors };
}

export function getFieldErrors(result: ValidationResult, field: string): string[] {
  return result.errors[field] || [];
}
