import { PasswordEntry } from '@/types';

const STORAGE_KEY = 'password-vault-entries';

export function getEntries(): PasswordEntry[] {
  if (typeof window === 'undefined') return [];
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : [];
  } catch {
    return [];
  }
}

export function saveEntries(entries: PasswordEntry[]): void {
  if (typeof window === 'undefined') return;
  localStorage.setItem(STORAGE_KEY, JSON.stringify(entries));
}

export function addEntry(entry: Omit<PasswordEntry, 'id' | 'createdAt' | 'updatedAt'>): PasswordEntry {
  const entries = getEntries();
  if (entries.some(e => e.name.toLowerCase() === entry.name.toLowerCase())) {
    throw new Error(`An entry named "${entry.name}" already exists`);
  }
  const newEntry: PasswordEntry = {
    ...entry,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  saveEntries([...entries, newEntry]);
  return newEntry;
}

export function updateEntry(id: string, updates: Partial<Omit<PasswordEntry, 'id' | 'createdAt'>>): PasswordEntry {
  const entries = getEntries();
  const index = entries.findIndex(e => e.id === id);
  if (index === -1) throw new Error('Entry not found');
  const updated: PasswordEntry = { ...entries[index]!, ...updates, updatedAt: new Date().toISOString() };
  entries[index] = updated;
  saveEntries(entries);
  return updated;
}

export function deleteEntry(id: string): void {
  saveEntries(getEntries().filter(e => e.id !== id));
}

export function searchEntries(query: string): PasswordEntry[] {
  const lowerQuery = query.toLowerCase();
  return getEntries().filter(e =>
    e.name.toLowerCase().includes(lowerQuery) ||
    e.username.toLowerCase().includes(lowerQuery) ||
    e.url?.toLowerCase().includes(lowerQuery)
  );
}
