import { calculatePoolSize } from './passwordGenerator';

export function analyzePassword(password: string) {
  const poolSize = calculatePoolSize(password);
  const length = password.length;
  const entropy = length * Math.log2(poolSize);

  return {
    password,
    poolSize,
    length,
    entropy,
    entropyFormula: `S = L \\cdot \\log_2(N) = ${length} \\cdot \\log_2(${poolSize}) = ${entropy.toFixed(2)} \\text{ bits}`,
    bruteForceTime: calculateTime(password),
    bruteForceFormula: generateBruteForceFormula(password),
    classification: classifyStrength(entropy),
    securityAssessment: assessSecurity(password),
  };
}

function generateBruteForceFormula(password: string): string {
  const poolSize = calculatePoolSize(password);
  const combinations = Math.pow(poolSize, password.length);
  return `T = \\frac{${poolSize}^{${password.length}}}{10^9} = ${combinations.toExponential(1)}`;
}

function calculateTime(password: string): string {
  const poolSize = calculatePoolSize(password);
  const seconds = Math.pow(poolSize, password.length) / 1e9;

  if (seconds < 1) return `${(seconds * 1000).toFixed(0)} ms`;
  if (seconds < 60) return `${seconds.toFixed(0)} s`;
  if (seconds < 3600) return `${(seconds / 60).toFixed(1)} min`;
  if (seconds < 86400) return `${(seconds / 3600).toFixed(1)} hr`;
  if (seconds < 31536000) return `${(seconds / 86400).toFixed(1)} days`;
  if (seconds < 3153600000) return `${(seconds / 31536000).toFixed(1)} yrs`;
  return `${(seconds / 3153600000).toFixed(1)} centuries`;
}

function classifyStrength(entropy: number): string {
  if (entropy < 40) return 'Weak: < 40 bits, crackable in seconds.';
  if (entropy < 60) return 'Fair: 40-60 bits, crackable in hours.';
  if (entropy < 80) return 'Good: 60-80 bits, crackable in months.';
  if (entropy < 100) return 'Strong: 80-100 bits, crackable in decades.';
  return 'Excellent: >= 100 bits, practically uncrackable.';
}

function assessSecurity(password: string): string {
  const seconds = Math.pow(calculatePoolSize(password), password.length) / 1e9;
  if (seconds < 60) return 'CRITICAL: Crackable in under a minute!';
  if (seconds < 86400) return 'WARNING: Crackable within a day.';
  if (seconds < 31536000) return 'MODERATE: Crackable within a year.';
  if (seconds < 315360000) return 'GOOD: Over a decade to crack.';
  return 'EXCELLENT: Over a century to crack.';
}
