import { validatePasswordStrength } from './passwordGenerator';
import type { PasswordEntry, ValidationResult, ValidationRules } from '@/types';

export const DEFAULT_RULES: ValidationRules = {
  required: ['name', 'username', 'password'],
  minLength: { name: 2, username: 3, password: 8 },
  maxLength: { name: 100, username: 255, password: 128, notes: 5000 },
  pattern: { url: /^(https?:\/\/)?[\w\-]+(\.[\w\-]+)+[/#?]?.*$/ },
  custom: {
    password: (v: string) => {
      if (!v) return 'Password required';
      const { strength, feedback } = validatePasswordStrength(v);
      return strength === 'weak' ? `Too weak: ${feedback.join(', ')}` : null;
    },
  },
};

export function validateEntry(
  entry: Partial<PasswordEntry>,
  rules: ValidationRules = DEFAULT_RULES
): ValidationResult {
  const errors: Record<string, string[]> = {};

  if (rules.required) {
    for (const field of rules.required) {
      const val = entry[field as keyof PasswordEntry];
      if (!val || (typeof val === 'string' && !val.trim())) {
        errors[field] = [`${field} is required`];
      }
    }
  }

  if (rules.minLength) {
    for (const [f, min] of Object.entries(rules.minLength)) {
      const val = entry[f as keyof PasswordEntry];
      if (val && typeof val === 'string' && val.length < min) {
        errors[f] = [`${f} must be >= ${min} chars`];
      }
    }
  }

  if (rules.maxLength) {
    for (const [f, max] of Object.entries(rules.maxLength)) {
      const val = entry[f as keyof PasswordEntry];
      if (val && typeof val === 'string' && val.length > max) {
        errors[f] = [`${f} must be <= ${max} chars`];
      }
    }
  }

  if (rules.pattern) {
    for (const [f, regex] of Object.entries(rules.pattern)) {
      const val = entry[f as keyof PasswordEntry];
      if (val && typeof val === 'string' && !regex.test(val)) {
        errors[f] = [`${f} format invalid`];
      }
    }
  }

  if (rules.custom) {
    for (const [f, validator] of Object.entries(rules.custom)) {
      const val = entry[f as keyof PasswordEntry];
      const err = validator(val);
      if (err) errors[f] = [err];
    }
  }

  return { valid: Object.keys(errors).length === 0, errors };
}

export function getErrors(result: ValidationResult, field: string): string[] {
  return result.errors[field] || [];
}
