import { PasswordEntry } from '@/types';

const KEY = 'password-vault';

export function getEntries(): PasswordEntry[] {
  if (typeof window === 'undefined') return [];
  try {
    const data = localStorage.getItem(KEY);
    return data ? JSON.parse(data) : [];
  } catch { return []; }
}

export function saveEntries(entries: PasswordEntry[]): void {
  if (typeof window === 'undefined') return;
  localStorage.setItem(KEY, JSON.stringify(entries));
}

export function addEntry(
  entry: Omit<PasswordEntry, 'id' | 'createdAt' | 'updatedAt'>
): PasswordEntry {
  const entries = getEntries();
  if (entries.some(e => e.name.toLowerCase() === entry.name.toLowerCase())) {
    throw new Error(`"${entry.name}" already exists`);
  }
  const newEntry: PasswordEntry = {
    ...entry,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
  };
  saveEntries([...entries, newEntry]);
  return newEntry;
}

export function updateEntry(
  id: string,
  updates: Partial<Omit<PasswordEntry, 'id' | 'createdAt'>>
): PasswordEntry {
  const entries = getEntries();
  const idx = entries.findIndex(e => e.id === id);
  if (idx === -1) throw new Error('Entry not found');
  const updated: PasswordEntry = {
    ...entries[idx]!,
    ...updates,
    updatedAt: new Date().toISOString(),
  };
  entries[idx] = updated;
  saveEntries(entries);
  return updated;
}

export function deleteEntry(id: string): void {
  saveEntries(getEntries().filter(e => e.id !== id));
}

export function searchEntries(query: string): PasswordEntry[] {
  const q = query.toLowerCase();
  return getEntries().filter(e =>
    e.name.toLowerCase().includes(q) ||
    e.username.toLowerCase().includes(q) ||
    e.url?.toLowerCase().includes(q)
  );
}
