'use client';

import { useState, useMemo, useEffect } from 'react';
import type { PasswordEntry } from '@/types';
import PasswordGenerator from '@/components/PasswordGenerator';
import PasswordForm from '@/components/PasswordForm';
import PasswordList from '@/components/PasswordList';
import { getEntries, addEntry, updateEntry, deleteEntry, searchEntries } from '@/lib/storage';

export default function Home() {
  const [entries, setEntries] = useState<PasswordEntry[]>([]);
  const [editing, setEditing] = useState<PasswordEntry | null>(null);
  const [showForm, setShowForm] = useState(false);
  const [search, setSearch] = useState('');
  const [tab, setTab] = useState<'entries' | 'generator'>('entries');

  useEffect(() => { setEntries(getEntries()); }, []);

  const filtered = useMemo(() => search ? searchEntries(search) : entries, [entries, search]);
  const existing = useMemo(() => entries.map(e => e.name.toLowerCase()), [entries]);

  const save = (entry: Omit<PasswordEntry, 'id' | 'createdAt' | 'updatedAt'>) => {
    try {
      if (editing) updateEntry(editing.id, entry);
      else addEntry(entry);
      setEntries(getEntries());
      setShowForm(false); setEditing(null);
    } catch (e) { alert(e instanceof Error ? e.message : 'Failed to save'); }
  };

  return (
    <main className="min-h-screen bg-gray-100">
      <header className="bg-white shadow border-b">
        <div className="max-w-6xl mx-auto px-4 py-4 flex justify-between">
          <h1 className="text-2xl font-bold">🔐 Password Manager</h1>
          <nav className="flex gap-4">
            <button onClick={() => setTab('entries')} className={`px-4 py-2 rounded ${tab === 'entries' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}>Entries ({entries.length})</button>
            <button onClick={() => setTab('generator')} className={`px-4 py-2 rounded ${tab === 'generator' ? 'bg-blue-600 text-white' : 'bg-gray-200'}`}>Generator</button>
          </nav>
        </div>
      </header>
      <div className="max-w-6xl mx-auto px-4 py-8">
        {tab === 'entries' ? (
          showForm ? (
            <PasswordForm entry={editing} onSave={save} onCancel={() => {setShowForm(false); setEditing(null);}} existingNames={existing} />
          ) : (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <div className="space-y-4">
                <button onClick={() => setShowForm(true)} className="w-full bg-blue-600 text-white py-3 rounded hover:bg-blue-700">+ Add Password</button>
                <input type="text" value={search} onChange={e => setSearch(e.target.value)} placeholder="Search..." className="w-full p-2 border rounded" />
              </div>
              <div className="lg:col-span-2">
                <PasswordList entries={filtered} onEdit={e => { setEditing(e); setShowForm(true); }} onDelete={id => { deleteEntry(id); setEntries(getEntries()); }} />
              </div>
            </div>
          )
        ) : (
          <div className="max-w-xl mx-auto"><PasswordGenerator /></div>
        )}
      </div>
    </main>
  );
}
