'use client';

import { useState, useEffect, useCallback } from 'react';
import type { PasswordEntry, ValidationResult } from '@/types';
import { getEntries, addEntry, updateEntry, deleteEntry, searchEntries } from '@/lib/storage';
import { validateEntry } from '@/lib/validation';

interface UsePasswordVaultReturn {
  entries: PasswordEntry[];
  loading: boolean;
  error: string | null;
  success: string | null;
  searchQuery: string;
  filteredEntries: PasswordEntry[];
  editingEntry: PasswordEntry | null;
  isFormOpen: boolean;
  existingNames: string[];

  // Actions
  setSearchQuery: (query: string) => void;
  openAddForm: () => void;
  openEditForm: (entry: PasswordEntry) => void;
  closeForm: () => void;
  saveEntry: (data: Omit<PasswordEntry, 'id' | 'createdAt' | 'updatedAt'>) => Promise<void>;
  removeEntry: (id: string) => Promise<void>;
  validateForm: (data: Partial<PasswordEntry>) => ValidationResult;
  clearMessages: () => void;
}

export function usePasswordVault(): UsePasswordVaultReturn {
  const [entries, setEntries] = useState<PasswordEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingEntry, setEditingEntry] = useState<PasswordEntry | null>(null);
  const [isFormOpen, setIsFormOpen] = useState(false);

  // Load entries on mount
  useEffect(() => {
    try {
      const data = getEntries();
      setEntries(data);
    } catch (e) {
      setError('Failed to load password vault');
    } finally {
      setLoading(false);
    }
  }, []);

  // Filter entries based on search
  const filteredEntries = searchQuery 
    ? searchEntries(searchQuery)
    : entries;

  const existingNames = entries.map(e => e.name.toLowerCase());

  const openAddForm = useCallback(() => {
    setEditingEntry(null);
    setIsFormOpen(true);
    clearMessages();
  }, []);

  const openEditForm = useCallback((entry: PasswordEntry) => {
    setEditingEntry(entry);
    setIsFormOpen(true);
    clearMessages();
  }, []);

  const closeForm = useCallback(() => {
    setIsFormOpen(false);
    setEditingEntry(null);
  }, []);

  const saveEntry = useCallback(async (data: Omit<PasswordEntry, 'id' | 'createdAt' | 'updatedAt'>) => {
    try {
      setLoading(true);
      setError(null);

      if (editingEntry) {
        updateEntry(editingEntry.id, data);
        setSuccess(`"${data.name}" updated successfully`);
      } else {
        addEntry(data);
        setSuccess(`"${data.name}" added to vault`);
      }

      setEntries(getEntries());
      closeForm();
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Failed to save entry');
    } finally {
      setLoading(false);
    }
  }, [editingEntry, closeForm]);

  const removeEntry = useCallback(async (id: string) => {
    try {
      const entry = entries.find(e => e.id === id);
      deleteEntry(id);
      setEntries(getEntries());
      setSuccess(`"${entry?.name}" deleted`);
    } catch (e) {
      setError('Failed to delete entry');
    }
  }, [entries]);

  const validateForm = useCallback((data: Partial<PasswordEntry>) => {
    return validateEntry(data);
  }, []);

  const clearMessages = useCallback(() => {
    setError(null);
    setSuccess(null);
  }, []);

  return {
    entries,
    loading,
    error,
    success,
    searchQuery,
    filteredEntries,
    editingEntry,
    isFormOpen,
    existingNames,
    setSearchQuery,
    openAddForm,
    openEditForm,
    closeForm,
    saveEntry,
    removeEntry,
    validateForm,
    clearMessages,
  };
}
