'use client';

import { useState, useCallback } from 'react';
import { generatePassword, validatePasswordStrength } from '@/lib/passwordGenerator';
import { analyzePassword } from '@/lib/formulas';
import type { GenerationOptions, PasswordStrength } from '@/types';

interface UsePasswordGeneratorReturn {
  password: string;
  strength: PasswordStrength;
  poolSize: number;
  entropy: number;
  showFormulas: boolean;
  options: GenerationOptions;
  validation: ReturnType<typeof validatePasswordStrength> | null;
  analysis: ReturnType<typeof analyzePassword> | null;

  setLength: (length: number) => void;
  toggleUppercase: () => void;
  toggleLowercase: () => void;
  toggleNumbers: () => void;
  toggleSymbols: () => void;
  generate: () => void;
  toggleFormulas: () => void;
  copyToClipboard: () => Promise<void>;
}

const defaultOptions: GenerationOptions = {
  length: 16,
  includeUppercase: true,
  includeLowercase: true,
  includeNumbers: true,
  includeSymbols: true,
};

export function usePasswordGenerator(): UsePasswordGeneratorReturn {
  const [password, setPassword] = useState('');
  const [strength, setStrength] = useState<PasswordStrength>('weak');
  const [poolSize, setPoolSize] = useState(0);
  const [showFormulas, setShowFormulas] = useState(false);
  const [options, setOptions] = useState<GenerationOptions>(defaultOptions);

  const validation = password ? validatePasswordStrength(password) : null;
  const analysis = password ? analyzePassword(password) : null;
  const entropy = analysis?.entropy || 0;

  const setLength = useCallback((length: number) => {
    setOptions(prev => ({ ...prev, length }));
  }, []);

  const toggleUppercase = useCallback(() => {
    setOptions(prev => ({ ...prev, includeUppercase: !prev.includeUppercase }));
  }, []);

  const toggleLowercase = useCallback(() => {
    setOptions(prev => ({ ...prev, includeLowercase: !prev.includeLowercase }));
  }, []);

  const toggleNumbers = useCallback(() => {
    setOptions(prev => ({ ...prev, includeNumbers: !prev.includeNumbers }));
  }, []);

  const toggleSymbols = useCallback(() => {
    setOptions(prev => ({ ...prev, includeSymbols: !prev.includeSymbols }));
  }, []);

  const generate = useCallback(() => {
    try {
      const result = generatePassword(options);
      setPassword(result.password);
      setStrength(result.strength);
      setPoolSize(result.poolSize);
    } catch (e) {
      // Handle error silently
    }
  }, [options]);

  const toggleFormulas = useCallback(() => {
    setShowFormulas(prev => !prev);
  }, []);

  const copyToClipboard = useCallback(async () => {
    if (password) {
      await navigator.clipboard.writeText(password);
    }
  }, [password]);

  return {
    password,
    strength,
    poolSize,
    entropy,
    showFormulas,
    options,
    validation,
    analysis,
    setLength,
    toggleUppercase,
    toggleLowercase,
    toggleNumbers,
    toggleSymbols,
    generate,
    toggleFormulas,
    copyToClipboard,
  };
}
