'use client';

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import type { PasswordEntry, PasswordStrength } from '@/types';
import { validateEntry, getFieldErrors } from '@/lib/validation';
import { generatePassword, validatePasswordStrength } from '@/lib/passwordGenerator';
import { analyzePassword } from '@/lib/formulas';
import StrengthMeter from './visuals/StrengthMeter';
import EntropyVisual from './visuals/EntropyVisual';
import Button from './ui/Button';
import Input from './ui/Input';

interface Props {
  entry?: PasswordEntry | null;
  onSave: (e: Omit<PasswordEntry, 'id' | 'createdAt' | 'updatedAt'>) => void;
  onCancel: () => void;
  existingNames?: string[];
}

const empty = { 
  name: '', username: '', password: '', url: '', notes: '', 
  tags: [] as string[], strength: 'weak' as PasswordStrength 
};

export default function EnhancedPasswordForm({ entry, onSave, onCancel, existingNames = [] }: Props) {
  const [data, setData] = useState(empty);
  const [errors, setErrors] = useState<Record<string, string[]>>({});
  const [showPwd, setShowPwd] = useState(false);
  const [tagInput, setTagInput] = useState('');
  const [showAnalysis, setShowAnalysis] = useState(false);

  useEffect(() => {
    if (entry) {
      setData({
        name: entry.name, 
        username: entry.username, 
        password: entry.password,
        url: entry.url || '', 
        notes: entry.notes || '', 
        tags: entry.tags || [], 
        strength: entry.strength,
      });
    } else {
      setData(empty);
    }
  }, [entry]);

  const handleChange = (field: keyof typeof data, val: any) => {
    setData(p => ({ ...p, [field]: val }));
    if (errors[field]) {
      setErrors(prev => { const n = {...prev}; delete n[field]; return n; });
    }
    if (field === 'password') {
      const { strength } = validatePasswordStrength(val);
      setData(p => ({ ...p, strength }));
      if (val.length > 0) setShowAnalysis(true);
    }
  };

  const addTag = () => {
    const t = tagInput.trim();
    if (t && !data.tags.includes(t)) {
      handleChange('tags', [...data.tags, t]);
      setTagInput('');
    }
  };

  const generate = () => {
    const { password, strength } = generatePassword({
      length: 20, includeUppercase: true, includeLowercase: true,
      includeNumbers: true, includeSymbols: true,
    });
    handleChange('password', password);
    handleChange('strength', strength);
    setShowAnalysis(true);
  };

  const submit = (e: React.FormEvent) => {
    e.preventDefault();
    const valErrors: Record<string, string[]> = {};

    if (data.name && existingNames.includes(data.name.toLowerCase())) {
      if (!entry || entry.name.toLowerCase() !== data.name.toLowerCase()) {
        valErrors.name = [`"${data.name}" already exists`];
      }
    }

    const validation = validateEntry({ 
      name: data.name, username: data.username, password: data.password 
    });

    if (!validation.valid || Object.keys(valErrors).length > 0) {
      setErrors({ ...validation.errors, ...valErrors });
      return;
    }
    onSave(data);
  };

  const analysis = data.password ? analyzePassword(data.password) : null;

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      className="bg-white rounded-2xl shadow-xl p-6 max-w-2xl mx-auto"
    >
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold">{entry ? 'Edit Password' : 'Add New Password'}</h2>
        {analysis && (
          <span className={`px-3 py-1 rounded-full text-sm font-medium ${
            data.strength === 'weak' ? 'bg-red-100 text-red-800' :
            data.strength === 'fair' ? 'bg-orange-100 text-orange-800' :
            data.strength === 'good' ? 'bg-yellow-100 text-yellow-800' :
            data.strength === 'strong' ? 'bg-green-100 text-green-800' :
            'bg-emerald-100 text-emerald-800'
          }`}>
            {data.strength.charAt(0).toUpperCase() + data.strength.slice(1)}
          </span>
        )}
      </div>

      <form onSubmit={submit} className="space-y-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <Input
            label="Name"
            value={data.name}
            onChange={e => handleChange('name', e.target.value)}
            placeholder="e.g., Gmail"
            error={getFieldErrors({ valid: true, errors }, 'name')[0]}
            required
          />
          <Input
            label="Username"
            value={data.username}
            onChange={e => handleChange('username', e.target.value)}
            placeholder="user@example.com"
            error={getFieldErrors({ valid: true, errors }, 'username')[0]}
            required
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">
            Password <span className="text-red-500">*</span>
          </label>
          <div className="flex gap-2">
            <div className="relative flex-1">
              <input
                type={showPwd ? 'text' : 'password'}
                value={data.password}
                onChange={e => handleChange('password', e.target.value)}
                className={`w-full px-4 py-2 border rounded-lg focus:outline-none focus:ring-2 transition-all ${
                  getFieldErrors({ valid: true, errors }, 'password').length 
                    ? 'border-red-500 focus:ring-red-200' 
                    : 'border-gray-300 focus:ring-blue-200 focus:border-blue-500'
                }`}
              />
              <button
                type="button"
                onClick={() => setShowPwd(!showPwd)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-500 hover:text-gray-700"
              >
                {showPwd ? '🙈' : '👁️'}
              </button>
            </div>
            <Button type="button" variant="secondary" onClick={generate} icon="🎲">
              Generate
            </Button>
          </div>
          {getFieldErrors({ valid: true, errors }, 'password').map((e, i) => (
            <p key={i} className="text-red-600 text-sm mt-1">{e}</p>
          ))}
        </div>

        {/* Strength Meter */}
        <AnimatePresence>
          {analysis && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
            >
              <StrengthMeter 
                strength={data.strength} 
                entropy={analysis.entropy}
              />

              {showAnalysis && (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  transition={{ delay: 0.2 }}
                  className="mt-4"
                >
                  <EntropyVisual 
                    password={data.password}
                    poolSize={analysis.poolSize}
                    entropy={analysis.entropy}
                  />
                </motion.div>
              )}
            </motion.div>
          )}
        </AnimatePresence>

        <Input
          label="URL (optional)"
          type="url"
          value={data.url}
          onChange={e => handleChange('url', e.target.value)}
          placeholder="https://example.com"
        />

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Tags</label>
          <div className="flex gap-2">
            <input
              type="text"
              value={tagInput}
              onChange={e => setTagInput(e.target.value)}
              onKeyPress={e => e.key === 'Enter' && (e.preventDefault(), addTag())}
              placeholder="Add tag..."
              className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-200"
