'use client';

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Card from './ui/Card';
import Button from './ui/Button';
import Input from './ui/Input';
import StrengthMeter from './visuals/StrengthMeter';
import EntropyVisual from './visuals/EntropyVisual';
import { generatePassword, validatePasswordStrength } from '@/lib/passwordGenerator';
import { analyzePassword } from '@/lib/formulas';
import { validateEntry, getFieldErrors } from '@/lib/validation';
import type { PasswordEntry, PasswordStrength, ValidationResult } from '@/types';

interface EnhancedPasswordFormProps {
  entry?: PasswordEntry | null;
  onSave: (data: Omit<PasswordEntry, 'id' | 'createdAt' | 'updatedAt'>) => void;
  onCancel: () => void;
  existingNames?: string[];
}

const DEFAULT_ENTRY = {
  name: '',
  username: '',
  password: '',
  url: '',
  notes: '',
  tags: [] as string[],
  strength: 'weak' as PasswordStrength,
};

export default function EnhancedPasswordForm({
  entry,
  onSave,
  onCancel,
  existingNames = [],
}: EnhancedPasswordFormProps) {
  const [formData, setFormData] = useState(DEFAULT_ENTRY);
  const [errors, setErrors] = useState<ValidationResult['errors']>({});
  const [showPassword, setShowPassword] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);
  const [tagInput, setTagInput] = useState('');

  // Initialize form when editing
  useEffect(() => {
    if (entry) {
      setFormData({
        name: entry.name,
        username: entry.username,
        password: entry.password,
        url: entry.url || '',
        notes: entry.notes || '',
        tags: entry.tags || [],
        strength: entry.strength,
      });
    } else {
      setFormData(DEFAULT_ENTRY);
    }
    setErrors({});
    setShowAnalysis(false);
  }, [entry]);

  const handleChange = useCallback((field: keyof typeof formData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));

    // Clear field errors on change
    if (errors[field]) {
      setErrors((prev) => {
        const next = { ...prev };
        delete next[field];
        return next;
      });
    }

    // Update strength on password change
    if (field === 'password') {
      const { strength } = validatePasswordStrength(value);
      setFormData((prev) => ({ ...prev, strength }));
      if (value.length > 0) setShowAnalysis(true);
    }
  }, [errors]);

  const generateNewPassword = useCallback(() => {
    try {
      const { password, strength } = generatePassword({
        length: 20,
        includeUppercase: true,
        includeLowercase: true,
        includeNumbers: true,
        includeSymbols: true,
      });

      setFormData((prev) => ({ ...prev, password, strength }));
      setShowPassword(true);
      setShowAnalysis(true);
    } catch {
      // Silent fail - generator validates internally
    }
  }, []);

