                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400">🔍</span>
                      <input type="text" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} placeholder="Search passwords..." className="w-full pl-10 pr-4 py-3 border rounded-lg" />
                    </div>
                    <Button onClick={() => { setEditingEntry(null); setShowForm(true); }} variant="primary" icon="➕" className="min-w-[140px]">Add</Button>
                  </div>

                  {/* List */}
                  <div className="space-y-3">
                    {filtered.length === 0 ? (
                      <Card className="p-8 text-center"><div className="text-4xl mb-2">🔐</div><p className="text-gray-500">No passwords yet. Add your first!</p></Card>
                    ) : (
                      filtered.map(entry => <PasswordItem key={entry.id} entry={entry} onEdit={handleEdit} onDelete={handleDelete} />)
                    )}
                  </div>
                </div>
              )}
            </motion.div>
          ) : (
            <motion.div key="generator" initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}>
              <EnhancedPasswordGenerator />
            </motion.div>
          )}
        </AnimatePresence>
      </main>

      <footer className="border-t mt-12 bg-white">
        <div className="max-w-6xl mx-auto px-4 py-4 text-center text-sm text-gray-500">
          Entropy Formula: S = L × log₂(N)
        </div>
      </footer>
    </div>
  );
}
